checker_dsl:
EXISTS (`data flow source node SRC`, `data flow sink node SNK`) {
  AND {
    EXISTS (`compile-time constant expression SPEC_EXPR`, `string value SPEC`) {
      AND {
        (`SPEC_EXPR has string value SPEC`),
        (`SPEC_EXPR equals SRC as expression`),
        (`SPEC matches pattern "RSA/%"`),
        NOT { (`SPEC matches pattern "%OAEP%"`) }
      }
    },
    EXISTS (`cryptographic algorithm specification CR`) {
      (`SNK as expression equals CR.getAlgoSpec()`)
    },
    (`there exists a data flow path from SRC to SNK`)
  }
}
